import android.util.Log;
import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.ResponseBody;

import java.io.IOException;

public class NetworkLoggerInterceptor implements Interceptor {

    private static final String TAG = "NetworkLogger";

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();

        // Log request information
        Log.d(TAG, "Request URL: " + request.url());
        Log.d(TAG, "Request Method: " + request.method());
        Log.d(TAG, "Request Headers: " + request.headers());

        if (request.body() != null) {
            String bodyString = request.body().toString();
            Log.d(TAG, "Request Body: " + bodyString);
        }

        // Proceed with the request
        Response response = chain.proceed(request);

        // Log response information
        Log.i(TAG, "Response Code: " + response.code());
        Log.i(TAG, "Response Headers: " + response.headers());

        if (response.body() != null) {
            String responseBodyString = response.body().string();
            Log.i(TAG, "Response Body: " + responseBodyString);

            // Rebuild the response to return it
            ResponseBody responseBody = ResponseBody.create(response.body().contentType(), responseBodyString);
            return response.newBuilder().body(responseBody).build();
        }

        return response;
    }
}